func ec_tell_frac(tls *libc.TLS, _this uintptr) (r1 opus_uint32) {
	var b, i, l, v2 int32
	var nbits, r opus_uint32
	_, _, _, _, _, _ = b, i, l, nbits, r, v2
	/*To handle the non-integral number of bits still left in the encoder/decoder
	   state, we compute the worst-case number of bits of val that must be
	   encoded to ensure that the value is inside the range for any possible
	   subsequent bits.
	  The computation here is independent of val itself (the decoder does not
	   even track that value), even though the real number of bits used after
	   ec_enc_done() may be 1 smaller if rng is a power of two and the
	   corresponding trailing bits of val are all zeros.
	  If we did try to track that special case, then coding a value with a
	   probability of 1/(1<<n) might sometimes appear to use more than n bits.
	  This may help explain the surprising result that a newly initialized
	   encoder or decoder claims to have used 1 bit.*/
	nbits = libc.Uint32FromInt32((*ec_ctx)(unsafe.Pointer(_this)).Fnbits_total << int32(BITRES))
	l = libc.Int32FromInt64(4)*libc.Int32FromInt32(__CHAR_BIT__) - libc.X__builtin_clz(tls, (*ec_ctx)(unsafe.Pointer(_this)).Frng)
	r = (*ec_ctx)(unsafe.Pointer(_this)).Frng >> (l - int32(16))
	i = int32(BITRES)
	for {
		v2 = i
		i = i - 1
		if !(v2 > 0) {
			break
		}
		r = r * r >> int32(15)
		b = libc.Int32FromUint32(r >> libc.Int32FromInt32(16))
		l = l<<int32(1) | b
		r = r >> libc.Uint32FromInt32(b)
		goto _1
	_1:
	}
	return nbits - libc.Uint32FromInt32(l)
}

