		sym = (*ec_dec)(unsafe.Pointer(_this)).Frem
		/*Read the next value from the input.*/
		(*ec_dec)(unsafe.Pointer(_this)).Frem = ec_read_byte(tls, _this)
		/*Take the rest of the bits we need from this new symbol.*/
