		xx = xx + opus_val32(*(*opus_val16)(unsafe.Pointer(x + uintptr(i)*4))**(*opus_val16)(unsafe.Pointer(x + uintptr(i)*4)))
		yy = yy + opus_val32(*(*opus_val16)(unsafe.Pointer(x + uintptr(i-T0)*4))**(*opus_val16)(unsafe.Pointer(x + uintptr(i-T0)*4)))
		goto _4
	_4:
