		if C<<int32(BITRES) > int32(3)*(int32(*(*opus_int16)(unsafe.Pointer((*OpusCustomMode)(unsafe.Pointer(m)).FeBands + uintptr(j+int32(1))*2)))-int32(*(*opus_int16)(unsafe.Pointer((*OpusCustomMode)(unsafe.Pointer(m)).FeBands + uintptr(j)*2))))<<LM<<int32(BITRES)>>int32(4) {
			v1 = C << int32(BITRES)
		} else {
			v1 = int32(3) * (int32(*(*opus_int16)(unsafe.Pointer((*OpusCustomMode)(unsafe.Pointer(m)).FeBands + uintptr(j+int32(1))*2))) - int32(*(*opus_int16)(unsafe.Pointer((*OpusCustomMode)(unsafe.Pointer(m)).FeBands + uintptr(j)*2)))) << LM << int32(BITRES) >> int32(4)
		}
		*(*int32)(unsafe.Pointer(thresh + uintptr(j)*4)) = v1
		/* Tilt of the allocation curve */
		*(*int32)(unsafe.Pointer(trim_offset + uintptr(j)*4)) = C * (int32(*(*opus_int16)(unsafe.Pointer((*OpusCustomMode)(unsafe.Pointer(m)).FeBands + uintptr(j+int32(1))*2))) - int32(*(*opus_int16)(unsafe.Pointer((*OpusCustomMode)(unsafe.Pointer(m)).FeBands + uintptr(j)*2)))) * (alloc_trim - int32(5) - LM) * (end - j - int32(1)) * (int32(1) << (LM + int32(BITRES))) >> int32(6)
