		X = Y>>libc.Int32FromInt32(16)*int32(A_fb1_20) + Y&libc.Int32FromInt32(0x0000FFFF)*int32(A_fb1_20)>>libc.Int32FromInt32(16)
		out_2 = *(*opus_int32)(unsafe.Pointer(S + 1*4)) + X
		*(*opus_int32)(unsafe.Pointer(S + 1*4)) = in32 + X
