		*(*opus_int32)(unsafe.Pointer(S)) = *(*opus_int32)(unsafe.Pointer(S)) + (out32_Q14>>libc.Int32FromInt32(16)*int32(int16(A0_U_Q28)) + out32_Q14&libc.Int32FromInt32(0x0000FFFF)*int32(int16(A0_U_Q28))>>libc.Int32FromInt32(16))
		*(*opus_int32)(unsafe.Pointer(S)) = *(*opus_int32)(unsafe.Pointer(S)) + (*(*opus_int32)(unsafe.Pointer(B_Q28 + 1*4))>>libc.Int32FromInt32(16)*int32(int16(inval)) + *(*opus_int32)(unsafe.Pointer(B_Q28 + 1*4))&libc.Int32FromInt32(0x0000FFFF)*int32(int16(inval))>>libc.Int32FromInt32(16))
		*(*opus_int32)(unsafe.Pointer(S + 1*4)) = ((out32_Q14>>libc.Int32FromInt32(16)*int32(int16(A1_L_Q28))+out32_Q14&libc.Int32FromInt32(0x0000FFFF)*int32(int16(A1_L_Q28))>>libc.Int32FromInt32(16))>>(libc.Int32FromInt32(14)-libc.Int32FromInt32(1)) + libc.Int32FromInt32(1)) >> libc.Int32FromInt32(1)
		*(*opus_int32)(unsafe.Pointer(S + 1*4)) = *(*opus_int32)(unsafe.Pointer(S + 1*4)) + (out32_Q14>>libc.Int32FromInt32(16)*int32(int16(A1_U_Q28)) + out32_Q14&libc.Int32FromInt32(0x0000FFFF)*int32(int16(A1_U_Q28))>>libc.Int32FromInt32(16))
		*(*opus_int32)(unsafe.Pointer(S + 1*4)) = *(*opus_int32)(unsafe.Pointer(S + 1*4)) + (*(*opus_int32)(unsafe.Pointer(B_Q28 + 2*4))>>libc.Int32FromInt32(16)*int32(int16(inval)) + *(*opus_int32)(unsafe.Pointer(B_Q28 + 2*4))&libc.Int32FromInt32(0x0000FFFF)*int32(int16(inval))>>libc.Int32FromInt32(16))
