		/* Update length. Sampling frequency may have changed */
		L = (*silk_decoder_state)(unsafe.Pointer(psDec)).Fframe_length
		/********************************************************/
		/* Run inverse NSQ                                      */
		/********************************************************/
		silk_decode_core(tls, psDec, bp, pOut, bp+140)
		/********************************************************/
		/* Update PLC state                                     */
		/********************************************************/
		silk_PLC(tls, psDec, bp, pOut, 0)
