		*(*float32)(unsafe.Pointer(px_win + uintptr(k+int32(2))*4)) = float32(float32(*(*float32)(unsafe.Pointer(px + uintptr(k+int32(2))*4))*libc.Float32FromFloat32(0.5)) * (S1 + S0))
