/* Redefine macro functions with extensive assertion in DEBUG mode.
   As functions can't be undefined, this file can't work with SigProcFIX_MacroCount.h */

// C documentation
//
//	/* fprintf(1, '%d, ', round(1024 * ([1 ./ (1 + exp(-(1:5))), 1] - 1 ./ (1 + exp(-(0:5)))))); */
var sigm_LUT_slope_Q10 = [6]opus_int32{
	0: int32(237),
	1: int32(153),
	2: int32(73),
	3: int32(30),
	4: int32(12),
	5: int32(7),
}

// C documentation
//
//	/* fprintf(1, '%d, ', round(32767 * 1 ./ (1 + exp(-(0:5))))); */
var sigm_LUT_pos_Q15 = [6]opus_int32{
	0: int32(16384),
	1: int32(23955),
	2: int32(28861),
	3: int32(31213),
	4: int32(32178),
	5: int32(32548),
}

// C documentation
//
//	/* fprintf(1, '%d, ', round(32767 * 1 ./ (1 + exp((0:5))))); */
var sigm_LUT_neg_Q15 = [6]opus_int32{
	0: int32(16384),
	1: int32(8812),
	2: int32(3906),
	3: int32(1554),
	4: int32(589),
	5: int32(219),
}

func silk_sigm_Q15(tls *libc.TLS, in_Q5 int32) (r int32) {
	var ind int32
	_ = ind
	if in_Q5 < 0 {
		/* Negative input */
		in_Q5 = -in_Q5
		if in_Q5 >= libc.Int32FromInt32(6)*libc.Int32FromInt32(32) {
			return 0 /* Clip */
		} else {
			/* Linear interpolation of look up table */
			ind = in_Q5 >> int32(5)
			return sigm_LUT_neg_Q15[ind] - int32(int16(sigm_LUT_slope_Q10[ind]))*int32(int16(in_Q5&libc.Int32FromInt32(0x1F)))
		}
	} else {
		/* Positive input */
		if in_Q5 >= libc.Int32FromInt32(6)*libc.Int32FromInt32(32) {
			return int32(32767) /* clip */
		} else {
			/* Linear interpolation of look up table */
			ind = in_Q5 >> int32(5)
			return sigm_LUT_pos_Q15[ind] + int32(int16(sigm_LUT_slope_Q10[ind]))*int32(int16(in_Q5&libc.Int32FromInt32(0x1F)))
		}
	}
	return r
}

